import{_ as t,o as r,c as o,a3 as a}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"61. Crisis Team Workload Management System Ctwms","description":"","frontmatter":{"title":"61. Crisis Team Workload Management System Ctwms","eba":"Mental Health Services 2024-2028","topics":["preliminary","definitions","staffing"]},"headers":[],"relativePath":"ebas/mental-health/common-terms/staffing/61-crisis-team-workload-management-system-ctwms.md","filePath":"ebas/mental-health/common-terms/staffing/61-crisis-team-workload-management-system-ctwms.md"}'),n={name:"ebas/mental-health/common-terms/staffing/61-crisis-team-workload-management-system-ctwms.md"};function s(i,e,l,m,c,d){return r(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="_61-crisis-team-workload-management-system-ctwms" tabindex="-1">61. Crisis Team Workload Management System Ctwms <a class="header-anchor" href="#_61-crisis-team-workload-management-system-ctwms" aria-label="Permalink to &quot;61. Crisis Team Workload Management System Ctwms&quot;">​</a></h1><p><strong>61.1</strong> Definition A crisis team means, for the purpose of this clause, ECATT, CATT, Triage or like service. Integrated teams which perform both crisis and case management functions will continue to utilise the Community Workload Management System at <a href="/eba/ebas/mental-health/common-terms/staffing/60-community-workload-management-system-cwms.html">clause 60</a>.</p><p><strong>61.2</strong> Workload Management Arrangement An Employee of a crisis team will be rostered the following time free from direct clinical care (non-direct clinical time):</p><p><strong>(a)</strong> 0.9 to 1 EFT – 2 clear days per month</p><p><strong>(b)</strong> 0.4 to 0.8 EFT – 1 clear day per month</p><p><strong>61.3</strong> Calculation of EFT</p><p><strong>(a)</strong> Subject to (b), the EFT referred to in 61.2 is contracted hours.</p><p><strong>(b)</strong> Where an employee formally increases their contracted hours for a single period greater than a fortnight as, the additional rostered hours will count for the purposes of the EFT referred to in clause 61.2.</p><p><strong>61.4</strong> Rosters</p><p><strong>(a)</strong> Non-direct dare clinical time will be marked on the roster when released in accordance with <a href="/eba/ebas/mental-health/rpn-pen-mho/hours-of-work/94-rosters.html">clause 94</a> (Rest breaks, rosters and meal breaks).</p><p><strong>(b)</strong> An Employee’s non-direct clinical time may be altered by the Employer once during the roster period. If, however, it is altered more than once and the Employee consequently performs direct clinical work during their previously rostered non-direct care clinical time, then such hours will be paid at overtime rates of pay.</p><p><strong>61.5</strong> Impact of paid planned leave on time free from direct clinical care.</p><p><strong>(a)</strong> For the purposes of this sub-clause a week is defined as half of the fortnightly contracted hours.</p><p><strong>(b)</strong> The entitlement at 61.2 will be reduced as follows:</p><p><strong>(i)</strong> 0.9 EFT to 1 EFT <strong>(A)</strong> Greater than 3 weeks of paid planned leave within the roster period will result in a reduction of 2 days of time free from direct clinical care for the roster period. <strong>(B)</strong> Greater than 1 week but not greater than 3 weeks of paid planned leave within the roster period will result in a reduction of 1 day of time free from direct clinical care for the roster period.</p><p><strong>(C)</strong> 1 week or less of paid planned leave within the roster period will result in no reduction of time free from direct clinical care for the roster period.</p><p><strong>(ii)</strong> 0.4 EFT to 0.8 EFT <strong>(A)</strong> Greater than 2 weeks of paid planned leave within the roster period will result in a reduction of 1 day of time free from direct clinical care period. <strong>(B)</strong> 2 weeks or less of paid planned leave within the roster period will result in no reduction of time free from direct clinical care for the roster period.</p><p><strong>(c)</strong> Any paid planned leave taken after the release of the roster will be considered in accordance with subclause 61.5 as part of the following roster period.</p>',18)])])}const f=t(n,[["render",s]]);export{h as __pageData,f as default};
